text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "conditions": [
          "스모크 테스트 통과"
        ]
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "확정된 공개 릴리스 결정이 아니다."
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견이 있었으나 담당자가 지정되지 않았다."
      },
      {
        "topic": "Hara의 tarball 경로 확인",
        "note": "Minjun의 스모크 결과 공유 이후 확인하기로 했으나 정확한 마감 시각은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": {
    "confirmed_actions": [
      {
        "owner": "Minjun",
        "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
        "due": "금요일 10:00 KST",
        "status": "대기",
        "source_certainty": "confirmed"
      },
      {
        "owner": "Doyun",
        "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
        "due": "금요일 12:00 KST",
        "status": "대기",
        "source_certainty": "confirmed"
      },
      {
        "owner": "Hara",
        "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
        "due": "미정",
        "status": "대기",
        "source_certainty": "confirmed_partial_due_unspecified"
      }
    ],
    "unassigned_or_not_confirmed": [
      {
        "owner": null,
        "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
        "due": "목요일(가능하면)",
        "status": "담당자 미정",
        "source_certainty": "mentioned_but_not_assigned"
      }
    ]
  },
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과 통과 여부를 먼저 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 failure triage note 작성 완료 여부를 확인한다.",
      "README 설치 절차 검토 담당자 지정이 필요한지 확인한다.",
      "최종 릴리스 승인 권한자 결정 여부를 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 결정 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일",
      "확정되지 않은 승인 권한자"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 제안은 결정으로 기록하지 않는다.",
    "수요일 릴리스는 내부 스트레치 목표로만 기록하고 확정 공개 일정으로 승격하지 않는다.",
    "Hara 작업의 정확한 마감은 미정으로 유지한다.",
    "README 검토는 담당자 미정 상태로 유지한다.",
    "오픈 질문은 답이 없는 상태로 유지하고 추론으로 채우지 않는다."
  ]
}
